(() => {  const root = document.documentElement;  const toggle = document.getElementById('theme-toggle');  const menuBtn = document.getElementById('menu-btn');  const mobileMenu = document.getElementById('mobile-menu');  const storedTheme = localStorage.getItem('ppm-theme');  if (storedTheme) root.setAttribute('data-theme', storedTheme);  toggle?.addEventListener('click', () => {    const next = root.getAttribute('data-theme') === 'dark' ? 'light' : 'dark';    root.setAttribute('data-theme', next);    localStorage.setItem('ppm-theme', next);    toggle.textContent = next === 'dark' ? '☀️ Light' : '🌙 Dark';  });  menuBtn?.addEventListener('click', () => mobileMenu?.classList.toggle('show'));  const initUpload = (wrapper) => {    const input = wrapper.querySelector('input[type=file]');    const zone = wrapper.querySelector('.upload-zone');    const preview = wrapper.querySelector('.preview');    const progress = wrapper.querySelector('.progress');    const processing = wrapper.querySelector('.processing');    const downloadArea = wrapper.querySelector('.download-area');    const progressBar = progress?.querySelector('span');    const complete = () => {      if (processing) processing.style.display = 'none';      if (downloadArea) downloadArea.style.display = 'block';    };    const runProgress = () => {      if (!progress || !progressBar) return;      progress.style.display = 'block';      if (processing) processing.style.display = 'block';      if (downloadArea) downloadArea.style.display = 'none';      let value = 0;      const timer = setInterval(() => {        value += 8;        progressBar.style.width = `${Math.min(value, 100)}%`;        if (value >= 100) {          clearInterval(timer);          complete();        }      }, 140);    };    const onFiles = (files) => {      if (!files || !files.length) return;      if (preview) {        preview.style.display = 'block';        preview.innerHTML = `<strong>Selected:</strong> ${files[0].name}<br/><small>${Math.round(files[0].size/1024)} KB</small>`;      }      runProgress();    };    zone?.addEventListener('click', () => input?.click());    input?.addEventListener('change', (e) => onFiles(e.target.files));    ['dragenter', 'dragover'].forEach((ev) => zone?.addEventListener(ev, (e)=>{e.preventDefault();zone.classList.add('drag');}));    ['dragleave', 'drop'].forEach((ev) => zone?.addEventListener(ev, (e)=>{e.preventDefault();zone.classList.remove('drag');}));    zone?.addEventListener('drop', (e) => {      if (input) input.files = e.dataTransfer.files;      onFiles(e.dataTransfer.files);    });  };  document.querySelectorAll('[data-upload-component]').forEach(initUpload);  const search = document.getElementById('tool-search');  const cards = Array.from(document.querySelectorAll('[data-tool-card]'));  search?.addEventListener('input', () => {    const q = search.value.trim().toLowerCase();    cards.forEach((card) => {      const text = (card.getAttribute('data-name') || card.textContent || '').toLowerCase();      card.style.display = text.includes(q) ? '' : 'none';    });  });})();